/**
 * Home component for the expense tracker. This component handles
 * displaying the user's transactions, calculating totals and
 * providing a form to add new entries. All data is stored in
 * localStorage, so the app continues to work offline without
 * external dependencies. The design uses Tailwind CSS classes
 * to provide a modern and responsive user interface.
 */
export const Home = () => {
  const { userID, name, photo, isAuth } = useAuth();
  const navigate = useNavigate();

  // Load transactions from localStorage or initialize with an empty array
  const [transactions, setTransactions] = useState(() => {
    const stored = localStorage.getItem('transactions');
    if (stored) {
      try {
        return JSON.parse(stored);
      } catch (e) {
        console.error('Failed to parse transactions from localStorage', e);
      }
    }
    return [];
  });

  // Form fields for new entry
  const [newExp, setNewExp] = useState('');
  const [newPrice, setNewPrice] = useState('');
  const [newType, setNewType] = useState('Expense');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Totals state: balance, income and expense
  const [total, setTotal] = useState({ balance: 0, income: 0, expense: 0 });

  // Recalculate totals whenever the transactions change
  useEffect(() => {
    let income = 0;
    let expense = 0;
    transactions.forEach((t) => {
      const amount = Number(t.price);
      if (t.type === 'Income') {
        income += amount;
      } else {
        expense += amount;
      }
    });
    setTotal({ balance: income - expense, income, expense });
  }, [transactions]);

  // Persist transactions to localStorage on every change
  useEffect(() => {
    localStorage.setItem('transactions', JSON.stringify(transactions));
  }, [transactions]);

  // Add a new transaction to the list
  const handleAdd = () => {
    if (!newExp.trim() || !newPrice) return;
    setIsSubmitting(true);
    setTimeout(() => {
      const newEntry = {
        id: Date.now().toString(),
        userID,
        exp: newExp.trim(),
        price: Number(newPrice),
        type: newType,
        createdAt: new Date().toISOString(),
      };
      setTransactions((prev) => [...prev, newEntry]);
      setNewExp('');
      setNewPrice('');
      setNewType('Expense');
      setIsSubmitting(false);
    }, 300);
  };

  // Delete a transaction by its id
  const handleDelete = (id) => {
    setTransactions((prev) => prev.filter((t) => t.id !== id));
  };

  // Sign the user out by clearing auth info and navigating to login
  const handleSignOut = () => {
    localStorage.removeItem('auth');
    navigate('/');
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && newExp.trim() && newPrice) {
      handleAdd();
    }
  };

  // Guard route: redirect unauthenticated users to the login page
  if (!isAuth) {
    return <Navigate to="/" />;
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-blue-50 to-slate-100">
      {/* Header */}
      <div className="bg-white border-b border-blue-100/50 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-5 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg bg-gradient-to-br from-blue-500 to-blue-600 flex items-center justify-center text-xl">
              💰
            </div>
            <h1 className="text-2xl font-bold text-gray-900">Budget Buddy</h1>
          </div>
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-full bg-gradient-to-br from-blue-400 to-blue-600 flex items-center justify-center text-white font-bold text-sm">
                {name.charAt(0).toUpperCase()}
              </div>
              <span className="text-sm font-semibold text-gray-900">{name}</span>
            </div>
            <button
              onClick={handleSignOut}
              className="px-4 py-2 text-sm font-semibold text-gray-700 hover:bg-gray-100 rounded-lg transition-colors"
            >
              Sign Out
            </button>
          </div>
        </div>
      </div>

      {/* Main content */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
        {/* Stats grid */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-10">
          {/* Balance Card */}
          <div className="bg-white rounded-xl shadow-md border border-blue-100/50 p-6 hover:shadow-lg transition-shadow">
            <div className="flex items-center justify-between mb-3">
              <p className="text-sm font-medium text-gray-600">Balance</p>
              <span className="text-2xl">⚖️</span>
            </div>
            <p className={`text-4xl font-bold ${total.balance >= 0 ? 'text-green-600' : 'text-red-600'}`}>
              ₹{Math.abs(total.balance).toLocaleString()}
            </p>
            <p className="text-xs text-gray-500 mt-3">
              {total.balance >= 0 ? '✓ Healthy balance' : '⚠ Budget deficit'}
            </p>
          </div>

          {/* Income Card */}
          <div className="bg-white rounded-xl shadow-md border border-green-100/50 p-6 hover:shadow-lg transition-shadow">
            <div className="flex items-center justify-between mb-3">
              <p className="text-sm font-medium text-gray-600">Income</p>
              <span className="text-2xl">📈</span>
            </div>
            <p className="text-4xl font-bold text-green-600">₹{total.income.toLocaleString()}</p>
            <p className="text-xs text-gray-500 mt-3">
              {transactions.filter(t => t.type === 'Income').length} transaction{transactions.filter(t => t.type === 'Income').length !== 1 ? 's' : ''}
            </p>
          </div>

          {/* Expense Card */}
          <div className="bg-white rounded-xl shadow-md border border-red-100/50 p-6 hover:shadow-lg transition-shadow">
            <div className="flex items-center justify-between mb-3">
              <p className="text-sm font-medium text-gray-600">Expenses</p>
              <span className="text-2xl">📉</span>
            </div>
            <p className="text-4xl font-bold text-red-600">₹{total.expense.toLocaleString()}</p>
            <p className="text-xs text-gray-500 mt-3">
              {transactions.filter(t => t.type === 'Expense').length} transaction{transactions.filter(t => t.type === 'Expense').length !== 1 ? 's' : ''}
            </p>
          </div>
        </div>

        {/* Content grid */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Add entry form */}
          <div className="bg-white rounded-xl shadow-md border border-blue-100/50 p-8">
            <h2 className="text-xl font-bold text-gray-900 mb-6 flex items-center gap-2">
              <span>➕</span> Add Entry
            </h2>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-2">
                  Description
                </label>
                <input
                  type="text"
                  placeholder="e.g., Groceries"
                  value={newExp}
                  onChange={(e) => setNewExp(e.target.value)}
                  onKeyPress={handleKeyPress}
                  disabled={isSubmitting}
                  className="w-full px-4 py-3 rounded-lg border-2 border-gray-200 focus:border-blue-500 focus:outline-none transition-all bg-gray-50 focus:bg-white text-gray-900 placeholder-gray-400 disabled:opacity-50 disabled:cursor-not-allowed"
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-2">
                  Amount
                </label>
                <input
                  type="number"
                  placeholder="0.00"
                  value={newPrice}
                  onChange={(e) => setNewPrice(e.target.value)}
                  onKeyPress={handleKeyPress}
                  disabled={isSubmitting}
                  className="w-full px-4 py-3 rounded-lg border-2 border-gray-200 focus:border-blue-500 focus:outline-none transition-all bg-gray-50 focus:bg-white text-gray-900 placeholder-gray-400 disabled:opacity-50 disabled:cursor-not-allowed"
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-3">
                  Type
                </label>
                <div className="flex gap-3">
                  <label className="flex-1">
                    <input
                      type="radio"
                      name="type"
                      value="Expense"
                      checked={newType === 'Expense'}
                      onChange={(e) => setNewType(e.target.value)}
                      className="sr-only"
                    />
                    <div className={`px-4 py-3 text-sm text-center font-semibold rounded-lg cursor-pointer border-2 transition-all ${
                      newType === 'Expense' 
                        ? 'border-red-500 bg-red-50 text-red-700' 
                        : 'border-gray-200 bg-white text-gray-700 hover:border-red-300'
                    }`}>
                      📉 Expense
                    </div>
                  </label>
                  <label className="flex-1">
                    <input
                      type="radio"
                      name="type"
                      value="Income"
                      checked={newType === 'Income'}
                      onChange={(e) => setNewType(e.target.value)}
                      className="sr-only"
                    />
                    <div className={`px-4 py-3 text-sm text-center font-semibold rounded-lg cursor-pointer border-2 transition-all ${
                      newType === 'Income' 
                        ? 'border-green-500 bg-green-50 text-green-700' 
                        : 'border-gray-200 bg-white text-gray-700 hover:border-green-300'
                    }`}>
                      📈 Income
                    </div>
                  </label>
                </div>
              </div>

              <button
                onClick={handleAdd}
                disabled={isSubmitting || !newExp.trim() || !newPrice}
                className="w-full bg-gradient-to-r from-blue-500 to-blue-600 hover:from-blue-600 hover:to-blue-700 disabled:from-gray-400 disabled:to-gray-500 text-white font-semibold py-3 px-4 rounded-lg transition-all duration-200 transform hover:scale-105 hover:shadow-lg active:scale-95 disabled:opacity-60 disabled:cursor-not-allowed disabled:transform-none shadow-md"
              >
                {isSubmitting ? 'Adding...' : 'Add Entry'}
              </button>
            </div>
          </div>

          {/* Transactions list */}
          <div className="lg:col-span-2 bg-white rounded-xl shadow-md border border-blue-100/50 p-8">
            <h2 className="text-xl font-bold text-gray-900 mb-6 flex items-center gap-2">
              <span>📋</span> Recent Transactions
            </h2>
            {transactions.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-12 text-center">
                <p className="text-5xl mb-4">📭</p>
                <p className="text-gray-600 font-medium">No transactions yet</p>
                <p className="text-gray-500 text-sm mt-1">Add your first transaction to get started</p>
              </div>
            ) : (
              <div className="space-y-2 max-h-96 overflow-y-auto custom-scrollbar">
                {transactions.map((tran) => (
                  <div
                    key={tran.id}
                    className={`flex justify-between items-center py-4 px-4 rounded-lg border-l-4 transition-all hover:shadow-md ${
                      tran.type === 'Expense'
                        ? 'bg-red-50 border-red-300 hover:bg-red-100'
                        : 'bg-green-50 border-green-300 hover:bg-green-100'
                    }`}
                  >
                    <div className="flex-1">
                      <p className="font-semibold text-gray-900">{tran.exp}</p>
                      <p className="text-xs text-gray-600 mt-1">
                        {new Date(tran.createdAt).toLocaleDateString('en-IN', {
                          month: 'short',
                          day: 'numeric',
                          year: 'numeric'
                        })}
                      </p>
                    </div>
                    <div className="flex items-center gap-4">
                      <span className={`text-lg font-bold ${tran.type === 'Expense' ? 'text-red-600' : 'text-green-600'}`}>
                        {tran.type === 'Expense' ? '−' : '+'}₹{Number(tran.price).toLocaleString()}
                      </span>
                      <button
                        onClick={() => handleDelete(tran.id)}
                        className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-100 rounded-lg transition-colors"
                        title="Delete transaction"
                      >
                        ✕
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Custom scrollbar styles */}
      <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: transparent;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #cbd5e1;
          border-radius: 3px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #94a3b8;
        }
      `}</style>
    </div>
  );
};
